143	struct EvalContext {
144		NetlistContext &netlist;
145		ProceduralContext *procedural;
146	
147		ast::EvalContext const_;
148		const ast::Expression *lvalue = nullptr;
149	
150		// Scope nest level tracking to isolate automatic variables of reentrant
151		// scopes (i.e. functions)
152		Yosys::dict<const ast::Scope *, int> scope_nest_level;
153	
154		int find_nest_level(const ast::Scope *scope);
155		Variable variable(const ast::ValueSymbol &symbol);
156	
157		RTLIL::SigSpec apply_conversion(const ast::ConversionExpression &conv, RTLIL::SigSpec op);
158		RTLIL::SigSpec apply_nested_conversion(const ast::Expression &expr, RTLIL::SigSpec val);
159		VariableBits streaming_lhs(ast::StreamingConcatenationExpression const &expr);
160		RTLIL::SigSpec streaming(ast::StreamingConcatenationExpression const &expr);
161	
162		// Evaluates the given symbols/expressions to their value in this context
163		RTLIL::SigSpec operator()(ast::Expression const &expr);
164	
165		// Evaluates the given expression using SVA rules.
166		// See IEEE Std 1800-2017 section 16.14.6
167		RTLIL::SigSpec sva(ast::Expression const &expr);
168	
169		// Evaluates the given expression, inserts an extra sign bit if need
170		// be so that the result can always be interpreted as a signed value
171		RTLIL::SigSpec eval_signed(ast::Expression const &expr);
172	
173		// Describes the given LHS expression in terms of `VariableBits`, if possible.
174		//
175		// This doesn't handle dynamic addressing and streaming expressions,
176		// the caller needs to handle those separately.
177		VariableBits lhs(ast::Expression const &expr, bool silent=false);
178	
179		// Helper for cases where the AST uses `EmptyArgument` on the RHS of
180		// an assignment as a stand-in for a value implied by the context
181		// (instance output connection or inside pattern assignments)
182		RTLIL::SigSpec connection_lhs(ast::AssignmentExpression const &assign);
183	
184		EvalContext(NetlistContext &netlist);
185		EvalContext(ProceduralContext &procedural);
186	
187		// for testing
188		bool ignore_ast_constants = false;
189	
190		// Variable reading within SVA is special depending on whether the variable
191		// is static, automatic, or is part of an expression casted to `const`
192		bool in_sva_expression = false;
