	}

	if (settings.empty_blackboxes.value_or(false)) {
		if (why_blackbox) {
			auto &note = why_blackbox->addNote(diag::NoteModuleBlackboxBecauseEmpty, sym.location);
			note << sym.name;
		}
		return is_decl_empty_module(*sym.getSyntax());
	}

