3305	{
3306		const ast::Scope *scope = symbol.getParentScope();
3307	
3308		while (true) {
3309			const ast::Symbol &scope_symbol = scope->asSymbol();
3310			if (scope_symbol.kind == ast::SymbolKind::Root) {
3311				// For special cases when the hierarchical value
3312				// is outside the hierarchy of modules
3313				// (e.g. a static variable inside a package).
3314				return nullptr;
3315			}
3316			if (scope_symbol.kind == ast::SymbolKind::InstanceBody) {
3317				auto parent = scope_symbol.as<ast::InstanceBodySymbol>().parentInstance;
3318				log_assert(parent->getParentScope());
3319				if (parent->getParentScope()->asSymbol().kind == ast::SymbolKind::Root
3320						|| !should_dissolve(*parent)) {
3321					return &scope_symbol.as<ast::InstanceBodySymbol>();
3322				} else {
3323					scope = parent->getParentScope();
