3332																	  	const ast::InstanceBodySymbol &b)
3333	{
3334		auto path = [&](const ast::InstanceBodySymbol *body) -> std::vector<const ast::InstanceBodySymbol*> {
3335			std::vector<const ast::InstanceBodySymbol*> path;
3336			path.push_back(body);
3337			while (body->parentInstance->getParentScope()->asSymbol().kind !=
3338						ast::SymbolKind::Root) {
3339				body = find_symbol_realm(*body->parentInstance);
3340				log_assert(body);
3341				path.push_back(body);
3342				log_assert(body->parentInstance);
3343				log_assert(body->parentInstance->getParentScope());
3344			}
3345			std::reverse(std::begin(path), std::end(path));
3346			return path;
3347		};
3348	
3349		auto pa = path(&a);
3350		auto pb = path(&b);
3351	
3352		size_t i = 0;
3353		for (; i < std::min(pa.size(), pb.size()); i++) {
3354			if (pa[i] != pb[i])
3355				break;
3356		}
3357		log_assert(i > 0);
3358		return *pa[i - 1];
